final class DecimalTextFormatter {
    static func sanitize(_ input: String) -> String {
        let allowed = CharacterSet(charactersIn: "0123456789.")
        let filtered = input.unicodeScalars.filter { allowed.contains($0) }
        var s = String(String.UnicodeScalarView(filtered))
        if let firstDot = s.firstIndex(of: ".") {
            let after = s.index(after: firstDot)
            let tail = s[after...].replacingOccurrences(of: ".", with: "")
            s = String(s[..<after]) + tail
        }
        return s
    }
    
    static func decimal(from input: String) -> Decimal? {
        let s = sanitize(input)
        return Decimal(string: s)
    }
}

