final class PinnedSessionDelegate: NSObject, URLSessionDelegate {
    private let pinnedSPKISHA256: Set<String>
    init(pinnedSPKISHA256: Set<String>) { self.pinnedSPKISHA256 = pinnedSPKISHA256 }
    
    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge,
                    completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let trust = challenge.protectionSpace.serverTrust else {
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        var error: CFError?
        guard SecTrustEvaluateWithError(trust, &error) else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        guard let cert = SecTrustGetCertificateAtIndex(trust, 0),
              let key = SecCertificateCopyKey(cert),
              let spki = SecKeyCopyExternalRepresentation(key, nil) as Data? else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        let hash = SHA256.hash(data: spki)
        let b64 = Data(hash).base64EncodedString()
        if pinnedSPKISHA256.isEmpty || pinnedSPKISHA256.contains(b64) {
            completionHandler(.useCredential, URLCredential(trust: trust))
        } else {
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }
}

final class APIClient {
    private let config: APIConfig
    private let session: URLSession
    private let encoder: JSONEncoder
    private let decoder: JSONDecoder
    
    init(config: APIConfig) {
        self.config = config
        let delegate = PinnedSessionDelegate(pinnedSPKISHA256: config.pinnedSPKISHA256)
        let cfg = URLSessionConfiguration.ephemeral
        cfg.waitsForConnectivity = true
        cfg.timeoutIntervalForRequest = 20
        cfg.timeoutIntervalForResource = 30
        cfg.httpAdditionalHeaders = [
            "Accept": "application/json",
            "Content-Type": "application/json"
        ]
        self.session = URLSession(configuration: cfg, delegate: delegate, delegateQueue: nil)
        self.encoder = JSONEncoder()
        self.encoder.dateEncodingStrategy = .custom { date, enc in
            var c = enc.singleValueContainer()
            try c.encode(Date.iso8601Formatter().string(from: date))
        }
        self.decoder = JSONDecoder()
        self.decoder.dateDecodingStrategy = .custom { dec in
            let c = try dec.singleValueContainer()
            let s = try c.decode(String.self)
            if let d = Date.iso8601Formatter().date(from: s) { return d }
            throw APIError.decoding("Invalid date: \(s)")
        }
    }
    
    private func sign(method: String, path: String, timestamp: String, body: Data?) -> String {
        let bodyHash = SHA256.hash(data: body ?? Data())
        let bodyHashHex = bodyHash.compactMap { String(format: "%02x", $0) }.joined()
        let canonical = "\(method.uppercased())\n\(path)\n\(timestamp)\n\(bodyHashHex)"
        let key = SymmetricKey(data: Data(config.apiSecret.utf8))
        let mac = HMAC<SHA256>.authenticationCode(for: Data(canonical.utf8), using: key)
        return Data(mac).base64EncodedString()
    }
    
    private func makeRequest<T: Encodable>(method: String, path: String, body: T?) throws -> URLRequest {
        let url = config.baseURL.appendingPathComponent(path)
        var req = URLRequest(url: url)
        req.httpMethod = method.uppercased()
        let ts = String(Int(Date().timeIntervalSince1970 * 1000))
        var bodyData: Data?
        if let body {
            do { bodyData = try encoder.encode(body) }
            catch { throw APIError.encoding(error.localizedDescription) }
            req.httpBody = bodyData
        }
        let sig = sign(method: method, path: "/\(path)", timestamp: ts, body: bodyData)
        req.setValue(config.apiKey, forHTTPHeaderField: "X-API-KEY")
        req.setValue(ts, forHTTPHeaderField: "X-TS")
        req.setValue(sig, forHTTPHeaderField: "X-SIGNATURE")
        return req
    }
    
    private func decodeErrorMessage(_ data: Data?) -> String? {
        guard let data, !data.isEmpty else { return nil }
        if let obj = try? JSONSerialization.jsonObject(with: data) as? [String: Any] {
            if let msg = obj["message"] as? String { return msg }
            if let err = obj["error"] as? String { return err }
        }
        return String(data: data, encoding: .utf8)
    }
    
    func send<Req: Encodable, Res: Decodable>(_ method: String, _ path: String, body: Req?) async throws -> Res {
        let req = try makeRequest(method: method, path: path, body: body)
        let (data, resp) = try await session.data(for: req)
        guard let http = resp as? HTTPURLResponse else { throw APIError.invalidResponse }
        guard (200..<300).contains(http.statusCode) else {
            throw APIError.http(http.statusCode, decodeErrorMessage(data))
        }
        do { return try decoder.decode(Res.self, from: data) }
        catch { throw APIError.decoding(error.localizedDescription) }
    }
    
    func sendNoBody<Res: Decodable>(_ method: String, _ path: String) async throws -> Res {
        struct Empty: Encodable {}
        return try await send(method, path, body: Optional<Empty>.none)
    }
}

