enum WSState: Equatable {
    case disconnected
    case connecting
    case connected
    case failed(String)
}

final class QuotesWebSocket: NSObject, ObservableObject, URLSessionWebSocketDelegate {
    @Published private(set) var state: WSState = .disconnected
    @Published private(set) var quotes: [String: Quote] = [:]
    
    private let url: URL
    private let apiKey: String
    private let apiSecret: String
    private let pinnedSPKISHA256: Set<String>
    
    private var session: URLSession!
    private var task: URLSessionWebSocketTask?
    private var reconnectTask: Task<Void, Never>?
    private var symbols: Set<String> = []
    
    init(url: URL, apiKey: String, apiSecret: String, pinnedSPKISHA256: Set<String>) {
        self.url = url
        self.apiKey = apiKey
        self.apiSecret = apiSecret
        self.pinnedSPKISHA256 = pinnedSPKISHA256
        super.init()
        let cfg = URLSessionConfiguration.ephemeral
        cfg.waitsForConnectivity = true
        self.session = URLSession(configuration: cfg, delegate: PinnedSessionDelegate(pinnedSPKISHA256: pinnedSPKISHA256), delegateQueue: nil)
    }
    
    func connect() {
        guard task == nil else { return }
        state = .connecting
        var req = URLRequest(url: url)
        let ts = String(Int(Date().timeIntervalSince1970 * 1000))
        let canonical = "WS\n/quotes\n\(ts)\n"
        let key = SymmetricKey(data: Data(apiSecret.utf8))
        let mac = HMAC<SHA256>.authenticationCode(for: Data(canonical.utf8), using: key)
        let sig = Data(mac).base64EncodedString()
        req.setValue(apiKey, forHTTPHeaderField: "X-API-KEY")
        req.setValue(ts, forHTTPHeaderField: "X-TS")
        req.setValue(sig, forHTTPHeaderField: "X-SIGNATURE")
        
        let t = session.webSocketTask(with: req)
        self.task = t
        t.resume()
        state = .connected
        listen()
        sendSubscribe()
        startPing()
    }
    
    func disconnect() {
        reconnectTask?.cancel()
        reconnectTask = nil
        task?.cancel(with: .goingAway, reason: nil)
        task = nil
        state = .disconnected
    }
    
    func setSymbols(_ symbols: [String]) {
        self.symbols = Set(symbols.map { $0.uppercased() })
        sendSubscribe()
    }
    
    private func sendSubscribe() {
        guard let task else { return }
        let payload: [String: Any] = ["type": "subscribe", "symbols": Array(symbols).sorted()]
        guard let data = try? JSONSerialization.data(withJSONObject: payload) else { return }
        task.send(.data(data)) { _ in }
    }
    
    private func startPing() {
        Task.detached { [weak self] in
            while let self, self.task != nil {
                try? await Task.sleep(nanoseconds: 15_000_000_000)
                await self.ping()
            }
        }
    }
    
    @MainActor private func ping() async {
        guard let task else { return }
        task.sendPing { [weak self] error in
            if let error {
                self?.handleFailure(error.localizedDescription)
            }
        }
    }
    
    private func listen() {
        guard let task else { return }
        task.receive { [weak self] result in
            guard let self else { return }
            switch result {
            case .failure(let err):
                self.handleFailure(err.localizedDescription)
            case .success(let msg):
                self.handleMessage(msg)
                self.listen()
            }
        }
    }
    
    private func handleMessage(_ msg: URLSessionWebSocketTask.Message) {
        let data: Data?
        switch msg {
        case .data(let d): data = d
        case .string(let s): data = s.data(using: .utf8)
        @unknown default: data = nil
        }
        guard let data else { return }
        if let obj = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
           let type = obj["type"] as? String {
            if type == "quote",
               let symbol = (obj["symbol"] as? String)?.uppercased(),
               let bid = obj["bid"] as? Double,
               let ask = obj["ask"] as? Double,
               let last = obj["last"] as? Double,
               let ts = obj["timestamp"] as? String,
               let date = Date.iso8601Formatter().date(from: ts) {
                let q = Quote(symbol: symbol, bid: Decimal(bid), ask: Decimal(ask), last: Decimal(last), timestamp: date)
                DispatchQueue.main.async {
                    self.quotes[symbol] = q
                }
            }
        }
    }
    
    private func handleFailure(_ message: String) {
        DispatchQueue.main.async {
            self.state = .failed(message)
        }
        scheduleReconnect()
    }
    
    private func scheduleReconnect() {
        guard reconnectTask == nil else { return }
        reconnectTask = Task.detached { [weak self] in
            guard let self else { return }
            var backoff: UInt64 = 1_000_000_000
            while !Task.isCancelled {
                try? await Task.sleep(nanoseconds: backoff)
                await MainActor.run {
                    self.task?.cancel(with: .abnormalClosure, reason: nil)
                    self.task = nil
                    self.state = .connecting
                }
                await MainActor.run { self.connect() }
                backoff = min(backoff * 2, 30_000_000_000)
            }
        }
    }
}

// MARK: - Trading Service

protocol TradingServiceProtocol {
    func fetchAccount() async throws -> AccountSnapshot
    func fetchPortfolio() async throws -> Portfolio
    func placeOrder(_ req: OrderRequest) async throws -> OrderResponse
    func fetchFills(limit: Int) async throws -> [TradeFill]
}

final class TradingService: TradingServiceProtocol {
    private let api: APIClient
    init(api: APIClient) { self.api = api }
    
    func fetchAccount() async throws -> AccountSnapshot {
        try await api.sendNoBody("GET", "v1/account")
    }
    
    func fetchPortfolio() async throws -> Portfolio {
        try await api.sendNoBody("GET", "v1/portfolio")
    }
    
    func placeOrder(_ req: OrderRequest) async throws -> OrderResponse {
        try await api.send("POST", "v1/orders", body: req)
    }
    
    func fetchFills(limit: Int) async throws -> [TradeFill] {
        struct Empty: Encodable {}
        return try await api.send("GET", "v1/fills?limit=\(limit)", body: Optional<Empty>.none)
    }
}

// MARK: - Demo Local Engine (Rapid Deployment Fallback)

final class LocalTradingEngine: TradingServiceProtocol, ObservableObject {
    @Published private(set) var portfolio: Portfolio
    @Published private(set) var fills: [TradeFill] = []
    private var quotes: [String: Quote] = [:]
    private let queue = DispatchQueue(label: "LocalTradingEngine")
    
    init() {
        self.portfolio = Portfolio(cash: 100_000, positions: [])
    }
    
    func updateQuote(_ quote: Quote) {
        queue.async {
            self.quotes[quote.symbol] = quote
        }
    }
    
    func fetchAccount() async throws -> AccountSnapshot {
        let p = await fetchPortfolio()
        let equity = computeEquity(portfolio: p)
        return AccountSnapshot(portfolio: p, equity: equity, dayPnL: 0, timestamp: Date())
    }
    
    func fetchPortfolio() async throws -> Portfolio {
        await withCheckedContinuation { cont in
            queue.async {
                cont.resume(returning: self.portfolio)
            }
        }
    }
    
    func fetchFills(limit: Int) async throws -> [TradeFill] {
        await withCheckedContinuation { cont in
            queue.async {
                cont.resume(returning: Array(self.fills.prefix(limit)))
            }
        }
    }
    
    func placeOrder(_ req: OrderRequest) async throws -> OrderResponse {
        try await withCheckedThrowingContinuation { cont in
            queue.async {
                let symbol = req.symbol.uppercased()
                let quote = self.quotes[symbol]
                let price: Decimal
                switch req.type {
                case .market:
                    price = quote?.last ?? 0
                case .limit:
                    price = req.limitPrice ?? 0
                }
                guard price > 0 else {
                    cont.resume(throwing: APIError.network("No price available for \(symbol)."))
                    return
                }
                
                let qty = req.quantity
                guard qty > 0 else {
                    cont.resume(throwing: APIError.encoding("Quantity must be > 0"))
                    return
                }
                
                let orderId = UUID().uuidString
                let ts = Date()
                
                var p = self.portfolio
                let cost = (qty * price).rounded(scale: 2)
                
                switch req.side {
                case .buy:
                    guard p.cash >= cost else {
                        cont.resume(returning: OrderResponse(orderId: orderId, status: .rejected, filledQuantity: 0, avgFillPrice: nil, message: "Insufficient cash", timestamp: ts))
                        return
                    }
                    p.cash -= cost
                    if let idx = p.positions.firstIndex(where: { $0.symbol == symbol }) {
                        let pos = p.positions[idx]
                        let newQty = pos.quantity + qty
                        let newAvg = ((pos.avgCost * pos.quantity) + (price * qty)) / newQty
                        p.positions[idx] = Position(symbol: symbol, quantity: newQty, avgCost: newAvg.rounded(scale: 4))
                    } else {
                        p.positions.append(Position(symbol: symbol, quantity: qty, avgCost: price.rounded(scale: 4)))
                    }
                case .sell:
                    guard let idx = p.positions.firstIndex(where: { $0.symbol == symbol }) else {
                        cont.resume(returning: OrderResponse(orderId: orderId, status: .rejected, filledQuantity: 0, avgFillPrice: nil, message: "No position", timestamp: ts))
                        return
                    }
                    let pos = p.positions[idx]
                    guard pos.quantity >= qty else {
                        cont.resume(returning: OrderResponse(orderId: orderId, status: .rejected, filledQuantity: 0, avgFillPrice: nil, message: "Insufficient shares", timestamp: ts))
                        return
                    }
                    p.cash += cost
                    let newQty = pos.quantity - qty
                    if newQty == 0 {
                        p.positions.remove(at: idx)
                    } else {
                        p.positions[idx] = Position(symbol: symbol, quantity: newQty, avgCost: pos.avgCost)
                    }
                }
                
                self.portfolio = p
                let fill = TradeFill(id: UUID().uuidString, symbol: symbol, side: req.side, quantity: qty, price: price, timestamp: ts, orderId: orderId)
                self.fills.insert(fill, at: 0)
                
                cont.resume(returning: OrderResponse(orderId: orderId, status: .filled, filledQuantity: qty, avgFillPrice: price, message: nil, timestamp: ts))
            }
        }
    }
    
    private func computeEquity(portfolio: Portfolio) -> Decimal {
        var equity = portfolio.cash
        for pos in portfolio.positions {
            let last = quotes[pos.symbol]?.last ?? pos.avgCost
            equity += (pos.quantity * last)
        }
        return equity.rounded(scale: 2)
    }
}

// MARK: - App State

@MainActor
final class AppState: ObservableObject {
    @Published var selectedSymbol: String = "AAPL"
    @Published var watchlist: [String] = ["AAPL", "MSFT", "NVDA", "TSLA", "AMZN"]
    
    @Published var account: AccountSnapshot?
    @Published var portfolio: Portfolio = Portfolio(cash: 0, positions: [])
    @Published var fills: [TradeFill] = []
    
    @Published var isPlacingOrder: Bool = false
    @Published var toast: ToastMessage?
    @Published var lastError: String?
    
    let quotesWS: QuotesWebSocket
    private let service: TradingServiceProtocol
    private let localEngine: LocalTradingEngine?
    private var cancellables: Set<AnyCancellable> = []
    
    init(service: TradingServiceProtocol, quotesWS: QuotesWebSocket, localEngine: LocalTradingEngine? = nil) {
        self.service = service
        self.quotesWS = quotesWS
        self.localEngine = localEngine
        
        quotesWS.$quotes
            .receive(on: DispatchQueue.main)
            .sink { [weak self] quotes in
                guard let self else { return }
                if let engine = self.localEngine {
                    for q in quotes.values { engine.updateQuote(q) }
                }
            }
            .store(in: &cancellables)
        
        quotesWS.$state
            .receive(on: DispatchQueue.main)
            .sink { [weak self] st in
                guard let self else { return }
                if case .failed(let msg) = st {
                    self.toast = ToastMessage(style: .warning, text: "Market data reconnecting: \(msg)")
                }
            }
            .store(in: &cancellables)
    }
    
    func start() {
        quotesWS.connect()
        quotesWS.setSymbols(watchlist)
        Task { await refreshAll() }
    }
    
    func refreshAll() async {
        do {
            async let a = service.fetchAccount()
            async let p = service.fetchPortfolio()
            async let f = service.fetchFills(limit: 50)
            let (account, portfolio, fills) = try await (a, p, f)
            self.account = account
            self.portfolio = portfolio
            self.fills = fills
        } catch {
            self.lastError = error.localizedDescription
            self.toast = ToastMessage(style: .error, text: error.localizedDescription)
        }
    }
    
    func updateWatchlist(_ list: [String]) {
        watchlist = list.map { $0.uppercased() }
        quotesWS.setSymbols(watchlist)
        if !watchlist.contains(selectedSymbol) {
            selectedSymbol = watchlist.first ?? "AAPL"
        }
    }
    
    func placeOrder(side: OrderSide, type: OrderType, qty: Decimal, limit: Decimal?, tif: TimeInForce) async {
        isPlacingOrder = true
        defer { isPlacingOrder = false }
        let req = OrderRequest(symbol: selectedSymbol.uppercased(),
                               side: side,
                               type: type,
                               quantity: qty,
                               limitPrice: type == .limit ? limit : nil,
                               timeInForce: tif,
                               clientOrderId: UUID().uuidString)
        do {
            let res = try await service.placeOrder(req)
            switch res.status {
            case .filled, .accepted, .partiallyFilled, .pending:
                toast = ToastMessage(style: .success, text: "Order \(res.status.rawValue): \(req.side.rawValue.uppercased()) \(Money.formatQty(qty)) \(req.symbol)")
            case .rejected, .canceled:
                toast = ToastMessage(style: .error, text: res.message ?? "Order \(res.status.rawValue)")
            }
            await refreshAll()
        } catch {
            toast = ToastMessage(style: .error, text: error.localizedDescription)
        }
    }
}

// MARK: - Toast

struct ToastMessage: Identifiable, Equatable {
    enum Style { case success, warning, error, info }
    let id = UUID()
    let style: Style
    let text: String
}

struct ToastView: View {
    let message: ToastMessage
    var body: some View {
        HStack(spacing: 10) {
            Circle()
                .fill(color)
                .frame(width: 10, height: 10)
            Text(message.text)
                .font(.subheadline)
                .foregroundStyle(.primary)
                .lineLimit(2)
            Spacer(minLength: 0)
        }
        .padding(.horizontal, 14)
        .padding(.vertical, 12)
        .background(.ultraThinMaterial)
        .clipShape(RoundedRectangle(cornerRadius: 14, style: .continuous))
        .overlay(
            RoundedRectangle(cornerRadius: 14, style: .continuous)
                .strokeBorder(Color.primary.opacity(0.08), lineWidth: 1)
        )
        .shadow(color: .black.opacity(0.12), radius: 12, x: 0, y: 6)
        .padding(.horizontal, 14)
        .padding(.top, 10)
    }
    
    private var color: Color {
        switch message.style {
        case .success: return .green
        case .warning: return .orange
        case .error: return .red
        case .info: return .blue
        }
    }
}

struct ToastHost: ViewModifier {
    @Binding var toast: ToastMessage?
    func body(content: Content) -> some View {
        ZStack(alignment: .top) {
            content
            if let toast {
                ToastView(message: toast)
                    .transition(.move(edge: .top).combined(with: .opacity))
                    .onAppear {
                        DispatchQueue.main.asyncAfter(deadline: .now() + 2.5) {
                            withAnimation(.spring(response: 0.35, dampingFraction: 0.9)) {
                                self.toast = nil
                            }
                        }
                    }
            }
        }
        .animation(.spring(response: 0.35, dampingFraction: 0.9), value: toast)
    }
}

extension View {
    func toast(_ toast: Binding<ToastMessage?>) -> some View {
        modifier(ToastHost(toast: toast))
    }
}

