struct TradeView: View {
    @EnvironmentObject var state: AppState
    @State private var side: OrderSide = .buy
    @State private var type: OrderType = .market
    @State private var tif: TimeInForce = .day
    @State private var qtyText: String = "1"
    @State private var limitText: String = ""
    @FocusState private var focus: Bool
    
    var body: some View {
        NavigationStack {
            VStack(spacing: 14) {
                headerCard
                orderTicket
                Spacer(minLength: 0)
            }
            .padding(.horizontal, 14)
            .padding(.top, 12)
            .navigationTitle("Trade")
            .toolbar {
                ToolbarItem(placement: .topBarTrailing) {
                    Button {
                        Task { await state.refreshAll() }
                    } label: {
                        Image(systemName: "arrow.clockwise")
                    }
                }
            }
        }
    }
    
    private var headerCard: some View {
        let symbol = state.selectedSymbol.uppercased()
        let quote = state.quotesWS.quotes[symbol]
        let last = quote?.last
        let bid = quote?.bid
        let ask = quote?.ask
        
        return VStack(alignment: .leading, spacing: 10) {
            HStack {
                SymbolPicker(selected: $state.selectedSymbol, symbols: state.watchlist)
                Spacer()
                ConnectionPill(state: state.quotesWS.state)
            }
            HStack(alignment: .firstTextBaseline) {
                Text(symbol)
                    .font(.title2).fontWeight(.semibold)
                Spacer()
                VStack(alignment: .trailing, spacing: 2) {
                    Text(last.map { Money.format($0) } ?? "—")
                        .font(.title3).fontWeight(.semibold)
                    Text(quote?.timestamp.formatted(date: .omitted, time: .standard) ?? "")
                        .font(.caption)
                        .foregroundStyle(.secondary)
                }
            }
            HStack {
                VStack(alignment: .leading, spacing: 2) {
                    Text("Bid").font(.caption).foregroundStyle(.secondary)
                    Text(bid.map { Money.format($0) } ?? "—").font(.subheadline).fontWeight(.medium)
                }
                Spacer()
                VStack(alignment: .leading, spacing: 2) {
                    Text("Ask").font(.caption).foregroundStyle(.secondary)
                    Text(ask.map { Money.format($0) } ?? "—").font(.subheadline).fontWeight(.medium)
                }
                Spacer()
                VStack(alignment: .leading, spacing: 2) {
                    Text("Cash").font(.caption).foregroundStyle(.secondary)
                    Text(Money.format(state.portfolio.cash)).font(.subheadline).fontWeight(.medium)
                }
            }
        }
        .padding(14)
        .background(.thinMaterial)
        .clipShape(RoundedRectangle(cornerRadius: 16, style: .continuous))
        .overlay(
            RoundedRectangle(cornerRadius: 16, style: .continuous)
                .strokeBorder(Color.primary.opacity(0.08), lineWidth: 1)
        )
    }
    
    private var orderTicket: some View {
        VStack(alignment: .leading, spacing: 12) {
            Text("Order Ticket")
                .font(.headline)
            
            HStack(spacing: 10) {
                SegmentedPill(selection: $side, items: OrderSide.allCases, title: { $0.rawValue.uppercased() })
                SegmentedPill(selection: $type, items: OrderType.allCases, title: { $0.rawValue.uppercased() })
            }
            
            HStack(spacing: 10) {
                VStack(alignment: .leading, spacing: 6) {
                    Text("Quantity").font(.caption).foregroundStyle(.secondary)
                    TextField("0", text: $qtyText)
                        .keyboardType(.decimalPad)
                        .textFieldStyle(.roundedBorder)
                        .focused($focus)
                        .onChange(of: qtyText) { _, new in qtyText = DecimalTextFormatter.sanitize(new) }
                }
                if type == .limit {
                    VStack(alignment: .leading, spacing: 6) {
                        Text("Limit Price").font(.caption).foregroundStyle(.secondary)
                        TextField("0.00", text: $limitText)
                            .keyboardType(.decimalPad)
                            .textFieldStyle(.roundedBorder)
                            .focused($focus)
                            .onChange(of: limitText) { _, new in limitText = DecimalTextFormatter.sanitize(new) }
                    }
                }
            }
            
            HStack(spacing: 10) {
                Picker("TIF", selection: $tif) {
                    ForEach(TimeInForce.allCases) { t in
                        Text(t.rawValue.uppercased()).tag(t)
                    }
                }
                .pickerStyle(.segmented)
            }
            
            orderSummary
            
            Button {
                focus = false
                Task {
                    let qty = DecimalTextFormatter.decimal(from: qtyText) ?? 0
                    let limit = DecimalTextFormatter.decimal(from: limitText)
                    await state.placeOrder(side: side, type: type, qty: qty, limit: limit, tif: tif)
                }
            } label: {
                HStack {
                    Spacer()
                    if state.isPlacingOrder {
                        ProgressView().tint(.white)
                    } else {
                        Text(buttonTitle).fontWeight(.semibold)
                    }
                    Spacer()
                }
                .padding(.vertical, 12)
            }
            .buttonStyle(.borderedProminent)
            .tint(side == .buy ? .green : .red)
            .disabled(!canSubmit || state.isPlacingOrder)
        }
        .padding(14)
        .background(Color(uiColor: .secondarySystemBackground))
        .clipShape(RoundedRectangle(cornerRadius: 16, style: .continuous))
        .overlay(
            RoundedRectangle(cornerRadius: 16, style: .continuous)
                .strokeBorder(Color.primary.opacity(0.06), lineWidth: 1)
        )
    }
    
    private var orderSummary: some View {
        let symbol = state.selectedSymbol.uppercased()
        let quote = state.quotesWS.quotes[symbol]
        let qty = DecimalTextFormatter.decimal(from: qtyText) ?? 0
        let px: Decimal? = {
            switch type {
            case .market: return quote?.last
            case .limit: return DecimalTextFormatter.decimal(from: limitText)
            }
        }()
        let est = (px ?? 0) * qty
        let fee = (est * Decimal(string: "0.0005")!).rounded(scale: 2)
        let total = (side == .buy ? (est + fee) : (est - fee)).rounded(scale: 2)
        
        return VStack(alignment: .leading, spacing: 8) {
            Divider().opacity(0.6)
            HStack {
                Text("Est. Notional").foregroundStyle(.secondary)
                Spacer()
                Text(Money.format(est.rounded(scale: 2))).fontWeight(.medium)
            }
            HStack {
                Text("Est. Fees").foregroundStyle(.secondary)
                Spacer()
                Text(Money.format(fee)).fontWeight(.medium)
            }
            HStack {
                Text(side == .buy ? "Est. Total" : "Est. Proceeds").foregroundStyle(.secondary)
                Spacer()
                Text(Money.format(total)).fontWeight(.semibold)
            }
        }
        .font(.subheadline)
    }
    
    private var canSubmit: Bool {
        let qty = DecimalTextFormatter.decimal(from: qtyText) ?? 0
        if qty <= 0 { return false }
        if type == .limit {
            let limit = DecimalTextFormatter.decimal(from: limitText) ?? 0
            if limit <= 0 { return false }
        }
        return true
    }
    
    private var buttonTitle: String {
        let symbol = state.selectedSymbol.uppercased()
        return "\(side.rawValue.uppercased()) \(symbol)"
    }
}

