struct SettingsView: View {
    @EnvironmentObject var state: AppState
    @State private var symbolsText: String = "AAPL,MSFT,NVDA,TSLA,AMZN"
    @State private var useLocalSim: Bool = false
    
    var body: some View {
        NavigationStack {
            Form {
                Section("Market Data") {
                    HStack {
                        Text("Connection")
                        Spacer()
                        ConnectionPill(state: state.quotesWS.state)
                    }
                }
                
                Section("Watchlist") {
                    TextField("Symbols (comma separated)", text: $symbolsText, axis: .vertical)
                        .textInputAutocapitalization(.characters)
                        .autocorrectionDisabled()
                    Button("Apply") {
                        let list = symbolsText
                            .split(separator: ",")
                            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() }
                            .filter { !$0.isEmpty }
                        state.updateWatchlist(list)
                    }
                }
                
                Section("Account") {
                    if let account = state.account {
                        HStack {
                            Text("Equity")
                            Spacer()
                            Text(Money.format(account.equity)).fontWeight(.semibold)
                        }
                        HStack {
                            Text("Day P&L")
                            Spacer()
                            Text(Money.format(account.dayPnL)).fontWeight(.semibold)
                        }
                        HStack {
                            Text("Updated")
                            Spacer()
                            Text(account.timestamp.formatted(date: .abbreviated, time: .standard))
                                .foregroundStyle(.secondary)
                        }
                    } else {
                        Text("Not loaded.")
                            .foregroundStyle(.secondary)
                    }
                }
                
                Section {
                    Button("Refresh") { Task { await state.refreshAll() } }
                }
            }
            .navigationTitle("Settings")
            .onAppear {
                symbolsText = state.watchlist.joined(separator: ",")
            }
        }
    }
}

// MARK: - Components

struct SymbolPicker: View {
    @Binding var selected: String
    let symbols: [String]
    
    var body: some View {
        Menu {
            ForEach(symbols, id: \.self) { s in
                Button(s.uppercased()) { selected = s.uppercased() }
            }
        } label: {
            HStack(spacing: 8) {
                Text(selected.uppercased())
                    .font(.subheadline).fontWeight(.semibold)
                Image(systemName: "chevron.down")
                    .font(.caption).fontWeight(.semibold)
                    .foregroundStyle(.secondary)
            }
            .padding(.horizontal, 10)
            .padding(.vertical, 8)
            .background(Color.primary.opacity(0.06))
            .clipShape(RoundedRectangle(cornerRadius: 10, style: .continuous))
        }
    }
}

struct ConnectionPill: View {
    let state: WSState
    var body: some View {
        HStack(spacing: 6) {
            Circle().fill(color).frame(width: 8, height: 8)
            Text(label)
                .font(.caption).fontWeight(.semibold)
                .foregroundStyle(.secondary)
        }
        .padding(.horizontal, 10)
        .padding(.vertical, 6)
        .background(Color.primary.opacity(0.06))
        .clipShape(Capsule())
    }
    
    private var label: String {
        switch state {
        case .disconnected: return "Offline"
        case .connecting: return "Connecting"
        case .connected: return "Live"
        case .failed: return "Reconnecting"
        }
    }
    
    private var color: Color {
        switch state {
        case .connected: return .green
        case .connecting: return .orange
        case .disconnected: return .gray
        case .failed: return .red
        }
    }
}

struct SegmentedPill<T: Hashable & Identifiable>: View {
    @Binding var selection: T
    let items: [T]
    let title: (T) -> String
    
    var body: some View {
        HStack(spacing: 0) {
            ForEach(items) { item in
                Button {
                    selection = item
                } label: {
                    Text(title(item))
                        .font(.caption).fontWeight(.semibold)
                        .foregroundStyle(selection.id == item.id ? Color.white : Color.primary)
                        .frame(maxWidth: .infinity)
                        .padding(.vertical, 10)
                        .background(selection.id == item.id ? Color.accentColor : Color.clear)
                }
            }
        }
        .background(Color.primary.opacity(0.06))
        .clipShape(RoundedRectangle(cornerRadius: 12, style: .continuous))
    }
}

struct PositionRow: View {
    let position: Position
    let quote: Quote?
    
    var body: some View {
        let last = quote?.last ?? position.avgCost
        let mktValue = (position.quantity * last).rounded(scale: 2)
        let cost = (position.quantity * position.avgCost).rounded(scale: 2)
        let pnl = (mktValue - cost).rounded(scale: 2)
        let pnlPct = cost == 0 ? 0 : (pnl / cost * 100).rounded(scale: 2)
        
        return HStack {
            VStack(alignment: .leading, spacing: 4) {
                Text(position.symbol).font(.headline)
                Text("\(Money.formatQty(position.quantity)) @ \(Money.format(position.avgCost))")
                    .font(.caption)
                    .foregroundStyle(.secondary)
            }
            Spacer()
            VStack(alignment: .trailing, spacing: 4) {
                Text(Money.format(mktValue)).fontWeight(.semibold)
                Text("\(pnl >= 0 ? "+" : "")\(Money.format(pnl)) (\(pnlPct.doubleValue, specifier: "%.2f")%)")
                    .font(.caption)
                    .foregroundStyle(pnl >= 0 ? .green : .red)
            }
        }
    }
}

struct FillRow: View {
    let fill: TradeFill
    var body: some View {
        HStack {
            VStack(alignment: .leading, spacing: 4) {
                Text("\(fill.side.rawValue.uppercased()) \(fill.symbol)")
                    .font(.headline)
                Text(fill.timestamp.formatted(date: .abbreviated, time: .standard))
                    .font(.caption)
                    .foregroundStyle(.secondary)
            }
            Spacer()
            VStack(alignment: .trailing, spacing: 4) {
                Text("\(Money.formatQty(fill.quantity)) @ \(Money.format(fill.price))")
                    .fontWeight(.semibold)
                Text("Order \(fill.orderId.prefix(8))")
                    .font(.caption)
                    .foregroundStyle(.secondary)
            }
        }
    }
}

// MARK: - App Bootstrap

@main
struct TradingApp: App {
    @StateObject private var state: AppState
    
    init() {
        let keychain = KeychainStore()
        
        let baseURL = URL(string: "https://api.yourbroker.com")!
        let wsURL = URL(string: "wss://stream.yourbroker.com/quotes")!
        
        let apiKey: String = (try? keychain.get("apiKey")).flatMap { String(data: $0, encoding: .utf8) } ?? "REPLACE_ME_API_KEY"
        let apiSecret: String = (try? keychain.get("apiSecret")).flatMap { String(data: $0, encoding: .utf8) } ?? "REPLACE_ME_API_SECRET"
        
        let pinned: Set<String> = [] // Add base64(SHA256(SPKI)) pins for production
        
        let config = APIConfig(baseURL: baseURL, apiKey: apiKey, apiSecret: apiSecret, pinnedSPKISHA256: pinned)
        let api = APIClient(config: config)
        
        let quotesWS = QuotesWebSocket(url: wsURL, apiKey: apiKey, apiSecret: apiSecret, pinnedSPKISHA256: pinned)
        
        let useLocalFallback = (apiKey.hasPrefix("REPLACE_ME") || apiSecret.hasPrefix("REPLACE_ME"))
        if useLocalFallback {
            let engine = LocalTradingEngine()
            _state = StateObject(wrappedValue: AppState(service: engine, quotesWS: quotesWS, localEngine: engine))
        } else {
            let service = TradingService(api: api)
            _state = StateObject(wrappedValue: AppState(service: service, quotesWS: quotesWS, localEngine: nil))
        }
    }
    
    var body: some Scene {
        WindowGroup {
            ContentView()
                .environmentObject(state)
        }
    }
}